package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
	"os"
	"path/filepath"
	"strings"

	"github.com/h2non/filetype"
)

const (
	maxUploadSize = 10 * 1024 * 1024 // 10 MB
	uploadDir     = "./uploads"
)

var allowedFileTypes = map[string]bool{
	"image/jpeg":  true,
	"image/png":   true,
	"application/pdf": true,
	"application/zip":  true,
	"application/x-zip-compressed": true,
}

func main() {
	http.HandleFunc("/upload", uploadHandler)
	http.ListenAndServe(":8080", nil)
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Invalid request method", http.StatusMethodNotAllowed)
		return
	}

	if err := r.ParseMultipartForm(maxUploadSize); err != nil {
		http.Error(w, "Unable to parse form", http.StatusBadRequest)
		return
	}

	file, _, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Unable to get file from form", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// Read the first 512 bytes to check the file type
	buf := make([]byte, 512)
	if _, err := file.Read(buf); err != nil {
		http.Error(w, "Unable to read file", http.StatusInternalServerError)
		return
	}
	filetype := filetype.GetType(buf)
	if !allowedFileTypes[filetype.MIME.Value] {
		http.Error(w, "File type not allowed", http.StatusBadRequest)
		return
	}

	// Reset file pointer
	file.Seek(0, 0)

	// Generate a safe filename
	filename := fmt.Sprintf("%s.%s", generateRandomString(10), filetype.Extension)
	filePath := filepath.Join(uploadDir, filename)

	// Save the file
	out, err := os.Create(filePath)
	if err != nil {
		http.Error(w, "Unable to save file", http.StatusInternalServerError)
		return
	}
	defer out.Close()

	if _, err := io.Copy(out, file); err != nil {
		http.Error(w, "Unable to save file", http.StatusInternalServerError)
		return
	}

	w.Write([]byte(fmt.Sprintf("File uploaded successfully: %s", filePath)))
}

func generateRandomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, n)
	for i := range b {
		b[i] = letters[rand.Intn(len(letters))]
	}
	return string(b)
}